code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { BrowserFrame, Image } from 'decantr/components';

code.example:
function ShowcaseGallery({ items }) {
  const { div, h2, p } = tags;

  return div({ class: css('_flex _col _gap8 _py12 _px6') },
    div({ class: css('_tc') },
      h2({ class: css('_heading2') }, 'Built with our framework'),
      p({ class: css('_body _fgmuted') }, 'See what developers are creating')
    ),
    div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6') },
      ...items.map(item =>
        div({ class: css('_trans[transform_0.3s_ease] _h:scale[1.02]') },
          BrowserFrame({ url: item.url },
            Image({ src: item.screenshot, alt: item.title, class: css('_wfull') })
          )
        )
      )
    )
  );
}

