import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Image } from 'decantr/components';

code.example:
function ShowcaseCards({ items }) {
  const { div, h2, h3, p } = tags;

  return div({ class: css('_flex _col _gap8 _py12 _px6') },
    div({ class: css('_tc') },
      h2({ class: css('_heading2') }, 'Featured Projects'),
      p({ class: css('_body _fgmuted') }, 'Explore what our community has built')
    ),
    div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6') },
      ...items.map(item =>
        Card({ class: css('_overflow[hidden] _trans[transform_0.3s_ease] _h:scale[1.02]') },
          Image({ src: item.screenshot, alt: item.title, class: css('_wfull _h[200px] _object[cover]') }),
          Card.Body({},
            h3({ class: css('_heading4') }, item.title),
            p({ class: css('_textsm _fgmuted') }, item.description)
          )
        )
      )
    )
  );
}

